// Validate the Firecrawl monitor webhook payload.
// Mirrors the schema in `oideachais/dlt_sources/domains/cross/upstream/blog_post.py`.
//
// Expected input shape:
//   { type: 'monitor.page.changed', data: { monitorId, package, blogPostType, changeSeverity, url, title, summary, isMeaningful, judgment, blogPost, apiChange } }
//
// We enforce:
//   1. package ∈ {motherduck, dlthub, lancedb, cocoindex}
//   2. isMeaningful === true (the Firecrawl LLM judge already filtered)
//   3. changeSeverity ∈ {low, medium, high, critical}
//   4. url is a valid https:// URL
//
// On failure: throw an error so n8n retries (max 3 attempts, then DLQ).

const item = $input.item.json;
const errors = [];

if (item.type !== 'monitor.page.changed') {
  errors.push(`unexpected event type: ${item.type}`);
}

const VALID_PACKAGES = ['motherduck', 'dlthub', 'lancedb', 'cocoindex'];
if (!VALID_PACKAGES.includes(item.data?.package)) {
  errors.push(`invalid package: ${item.data?.package}`);
}

if (item.data?.isMeaningful !== true) {
  errors.push('isMeaningful must be true (Firecrawl judge already filtered)');
}

const VALID_SEVERITIES = ['low', 'medium', 'high', 'critical'];
if (!VALID_SEVERITIES.includes(item.data?.changeSeverity)) {
  errors.push(`invalid changeSeverity: ${item.data?.changeSeverity}`);
}

if (!item.data?.url || !item.data.url.startsWith('https://')) {
  errors.push(`invalid url: ${item.data?.url}`);
}

if (errors.length > 0) {
  throw new Error(`upstream-blog-monitor validation failed: ${errors.join('; ')}`);
}

return [
  {
    json: {
      metadata: {
        package: item.data.package,
        blog_post_type: item.data.blogPostType || 'unknown',
        first_seen_at: item.data.firstSeenAt || new Date().toISOString(),
        firecrawl_monitor_id: item.data.monitorId,
        change_severity: item.data.changeSeverity,
        url: item.data.url,
        title: item.data.title,
        summary: item.data.summary,
        is_meaningful: item.data.isMeaningful,
        judgment_confidence: item.data.judgment?.confidence || 'low',
      },
      blog_post: item.data.blogPost || {},
      api_change: item.data.apiChange || {},
    },
  },
];

// Build the JSONL content from the validated payload.
// One line per webhook event (so the DLT incremental source can
// detect duplicates via the (package, delivery_id) audit table).

const meta = $json.metadata;
const blogPost = $json.blog_post;
const apiChange = $json.api_change;

const payload = {
  metadata: meta,
  blog_post: blogPost,
  api_change: apiChange,
};

return [
  {
    json: {
      ...$json,
      _jsonl: JSON.stringify(payload),
    },
  },
];

// Trigger the Dagster asset `upstream_blog_monitor_ingest` via the
// Dagster GraphQL `LAUNCH_PARTITION_BACKFILL_MUTATION`. We use the
// `all_assets` job (defined in oideachais/dagster_defs/jobs.py) with
// a partition run that targets just this one asset.
//
// Endpoint: https://dagster.cianfhoghlaim.ie/graphql
// Auth: via the n8n `dagster-api` credential (Locket-injected at runtime).

const endpoint = 'https://dagster.cianfhoghlaim.ie/graphql';
const mutation = `
  mutation LaunchRun($executionParams: ExecutionParams!) {
    launchRun(executionParams: $executionParams) {
      __typename
      ... on LaunchRunSuccess {
        run {
          runId
          status
        }
      }
      ... on RunNotFoundError {
        message
      }
      ... on PythonError {
        message
      }
    }
  }
`;

const variables = {
  executionParams: {
    selector: {
      jobName: 'upstream_monitoring_job',
    },
    runConfigData: {
      assets: {
        one_of_asset_keys: [
          {
            path: ['upstream_blog_monitor_ingest'],
          },
        ],
      },
    },
    tags: [
      { key: 'package', value: $json.metadata.package },
      { key: 'firecrawl_monitor_id', value: $json.metadata.firecrawl_monitor_id },
      { key: 'source', value: 'upstream-blog-monitor-n8n' },
    ],
  },
};

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: endpoint,
  headers: {
    'Content-Type': 'application/json',
    Authorization: `Bearer ${$env.DAGSTER_GRAPHQL_TOKEN}`,
  },
  body: {
    query: mutation,
    variables: variables,
  },
  json: true,
});

return [
  {
    json: {
      ...$json,
      dagster_run_id: response.data?.data?.launchRun?.run?.runId,
      dagster_run_status: response.data?.data?.launchRun?.run?.status,
    },
  },
];
